/**
 * 📦 KZM Library - Kuzmo Memory Packet (v1.0)
 * =============================================
 * 크로스 플랫폼 단일 추억 포맷.
 * Web / Android (Capacitor) / PC (C# Bridge) 공통.
 *
 * .kzm = JSON (manifest + files in Base64)
 */

// ─── PACK ────────────────────────────────────────────────
/**
 * 이벤트 데이터 → .kzm Blob 패킹
 * @param {Object} ev  - eventStore의 이벤트 객체
 * @returns {Blob}     - .kzm Blob (application/x-kzm)
 */
export async function packKzm(ev) {
    const files = {};
    const mediaMap = {};

    // 1. .md 콘텐츠 생성
    const mdContent = buildMarkdown(ev);
    files['content.md'] = btoa(unescape(encodeURIComponent(mdContent)));
    mediaMap['content.md'] = 'note';

    // 2. 이미지 바이너리 수집
    if (ev.imageUrl && ev.imageUrl !== 'null') {
        try {
            const blob = await fetchBlobSafe(ev.imageUrl);
            if (blob) {
                files['thumbnail.jpg'] = await blobToBase64(blob);
                mediaMap['thumbnail.jpg'] = 'thumbnail';
            }
        } catch { /* 미디어 실패 시 스킵 */ }
    }

    // 3. 오디오 바이너리 수집
    if (ev.audioUrl && ev.audioUrl !== 'null') {
        try {
            const blob = await fetchBlobSafe(ev.audioUrl);
            if (blob) {
                const ext = getExtension(ev.audioUrl) || 'mp3';
                const audioKey = `voice.${ext}`;
                files[audioKey] = await blobToBase64(blob);
                mediaMap[audioKey] = 'audio';
            }
        } catch { /* 오디오 실패 시 스킵 */ }
    }

    const packet = {
        _kzm: '1.0',
        manifest: {
            id: ev.id,
            title: ev.title,
            lat: ev.lat,
            lng: ev.lng,
            region: ev.region || 'Unknown',
            tags: ev.tags || [],
            category: ev.type || ev.category || 'memory',
            timestamp: ev.timestamp || Date.now(),
            snippet: buildSnippet(ev),
            mediaMap,
        },
        files,
    };

    const json = JSON.stringify(packet);
    return new Blob([json], { type: 'application/x-kzm' });
}

// ─── UNPACK ──────────────────────────────────────────────
/**
 * .kzm Blob / JSON 문자열 → 이벤트 객체 로드
 * @param {Blob|string} input
 * @returns {{ ev: Object, files: Object }}
 */
export async function unpackKzm(input) {
    let json;
    if (input instanceof Blob) {
        json = await input.text();
    } else {
        json = input;
    }
    const packet = JSON.parse(json);

    if (!packet._kzm) throw new Error('Invalid .kzm packet');

    const { manifest, files } = packet;
    let imageUrl = null;
    let audioUrl = null;

    // 미디어 복원: Base64 → Blob URL
    if (files) {
        for (const [name, b64] of Object.entries(files)) {
            const role = manifest.mediaMap?.[name];
            const blob = base64ToBlob(b64, guessMime(name));
            const blobUrl = createKzmUrl(blob);

            if (role === 'thumbnail') imageUrl = blobUrl;
            else if (role === 'audio') audioUrl = blobUrl;
        }
    }

    const ev = {
        id: manifest.id,
        title: manifest.title,
        lat: manifest.lat,
        lng: manifest.lng,
        region: manifest.region,
        tags: manifest.tags,
        type: manifest.category,
        timestamp: manifest.timestamp,
        summary: manifest.snippet,
        content: files?.['content.md']
            ? decodeURIComponent(escape(atob(files['content.md'])))
            : manifest.snippet,
        imageUrl,
        audioUrl,
        _kzmPacket: packet, // 원본 보관
    };

    return ev;
}

// ─── THUMBNAIL EXTRACTION ────────────────────────────────
/**
 * 이미지 URL → 썸네일 Blob (200×200 축소)
 * IndexedDB 슬림 캐시용.
 */
export async function extractThumbnail(imageUrl) {
    if (!imageUrl || imageUrl === 'null') return null;
    try {
        const blob = await fetchBlobSafe(imageUrl);
        if (!blob) return null;

        const bmp = await createImageBitmap(blob, {
            resizeWidth: 200,
            resizeHeight: 200,
            resizeQuality: 'medium',
        });

        const canvas = new OffscreenCanvas(200, 200);
        const ctx = canvas.getContext('2d');
        ctx.drawImage(bmp, 0, 0);
        return canvas.convertToBlob({ type: 'image/jpeg', quality: 0.7 });
    } catch {
        return null;
    }
}

// ─── SLIM CACHE BUILDER ──────────────────────────────────
/**
 * 이벤트 → IndexedDB용 슬림 레코드 변환
 */
export async function buildSlimRecord(ev) {
    const thumbnailBlob = await extractThumbnail(ev.imageUrl || null);
    return {
        id: ev.id,
        title: ev.title,
        lat: ev.lat,
        lng: ev.lng,
        region: ev.region || 'Unknown',
        tags: ev.tags || [],
        timestamp: ev.timestamp || Date.now(),
        snippet: buildSnippet(ev),
        thumbnailBlob: thumbnailBlob || null,
        packetDriveId: ev.packetDriveId || null,
        localKzmPath: ev.localKzmPath || null,
        type: ev.type || 'memory',
    };
}

// ─── BLOB URL MANAGER ────────────────────────────────────
const activeBlobUrls = new Set();

/** 🧹 모든 KZM 관련 임시 URL 해제 (메모리 누수 방지) */
export function revokeAllKzmUrls() {
    activeBlobUrls.forEach(url => URL.revokeObjectURL(url));
    activeBlobUrls.clear();
    console.log("🧹 [KZM] All temporary Blob URLs revoked.");
}

// ─── HELPERS ─────────────────────────────────────────────
function buildSnippet(ev) {
    const raw = ev.content || ev.description || ev.summary || '';
    const lines = raw.trim().split('\n').filter(l => l.trim());
    return lines.slice(0, 2).join(' ').substring(0, 120);
}

function buildMarkdown(ev) {
    const date = new Date(ev.timestamp || Date.now()).toLocaleString('ko-KR');
    return [
        '---',
        `id: ${ev.id}`,
        `title: "${ev.title}"`,
        `region: ${ev.region || 'Unknown'}`,
        `lat: ${ev.lat}`,
        `lng: ${ev.lng}`,
        `category: ${ev.type || ev.category || 'memory'}`,
        `imageUrl: ${ev.imageUrl || 'null'}`,
        `audioUrl: ${ev.audioUrl || 'null'}`,
        `tags: [${(ev.tags || []).map(t => `"${t}"`).join(', ')}]`,
        `created_at: ${date}`,
        '---',
        '',
        `# ${ev.title}`,
        '',
        ev.content || ev.description || ev.summary || '내용 없음',
        '',
        '---',
        '*Kuzmo Memory Packet v1.1*',
    ].join('\n');
}

async function fetchBlobSafe(url) {
    // 🛡️ [CORS-POLBACK] no-cors 대신 기본 fetch 사용 (동일 도메인/Drive 허용)
    const res = await fetch(url).catch(() => null);
    if (!res || !res.ok) return null;
    return res.blob();
}

function blobToBase64(blob) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result.split(',')[1]);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
    });
}

function base64ToBlob(b64, mime) {
    const binary = atob(b64);
    const arr = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) arr[i] = binary.charCodeAt(i);
    return new Blob([arr], { type: mime });
}

function createKzmUrl(blob) {
    const url = URL.createObjectURL(blob);
    activeBlobUrls.add(url);
    return url;
}

function guessMime(filename) {
    if (filename.endsWith('.jpg') || filename.endsWith('.jpeg')) return 'image/jpeg';
    if (filename.endsWith('.png')) return 'image/png';
    if (filename.endsWith('.mp3')) return 'audio/mpeg';
    if (filename.endsWith('.aac')) return 'audio/aac';
    if (filename.endsWith('.ogg')) return 'audio/ogg';
    if (filename.endsWith('.md')) return 'text/markdown';
    return 'application/octet-stream';
}

function getExtension(url) {
    try {
        const path = new URL(url).pathname;
        const parts = path.split('.');
        return parts.length > 1 ? parts[parts.length - 1] : null;
    } catch {
        return null;
    }
}
